//! Integration tests for workflow parsing, config extraction, and Liquid rendering.
//!
//! These tests define the verification contract for slice S02.  They compile
//! against stub implementations and are expected to fail at runtime until the
//! corresponding implementation tasks complete.

use std::io::Write;
use tempfile::NamedTempFile;

use symphony::config::{from_workflow, validate};
use symphony::domain::{ServiceConfig, TrackerConfig};
use symphony::error::SymphonyError;
use symphony::workflow::parse_workflow;
use symphony::workflow_store::WorkflowStore;

