/// Symphony requires strict-variables mode: unknown variables must produce an
/// error rather than render as empty string.  This test will fail until strict
/// mode is wired in the implementation.
#[test]
fn test_liquid_unknown_variable_error() {
    let parser = liquid::ParserBuilder::with_stdlib()
        .build()
        .expect("liquid parser should build");

    let template = parser
        .parse("{{ unknown_var }}")
        .expect("template string should parse");

    let globals = liquid::object!({});
    let result = template.render(&globals);

    // In strict-variables mode (required by spec §10.4), rendering an unknown
    // variable must return Err.  The default liquid behaviour returns Ok(""),
    // which is why this assertion fails until strict mode is implemented.
    assert!(
        result.is_err(),
        "strict mode should error on unknown variables; got Ok: {:?}",
        result.ok()
    );
}

#[test]
fn test_liquid_known_variables_render() {
    let parser = liquid::ParserBuilder::with_stdlib()
        .build()
        .expect("liquid parser should build");

    let template = parser
        .parse("{{ issue_id }}")
        .expect("template string should parse");

    let globals = liquid::object!({ "issue_id": "LIN-1" });
    let output = template.render(&globals).expect("render should succeed");

    assert_eq!(output, "LIN-1");
}

